const ha = global.get("homeassistant").homeAssistant.states;

function getNum(entity) {
    if (!entity || !ha[entity]) return 0;
    return Number(ha[entity].state) || 0;
}

msg.payload = {
    solar: getNum(env.get("SOLAR_ENERGY_ENTITY")),
    load: getNum(env.get("LOAD_ENERGY_ENTITY")),
    grid: getNum(env.get("GRID_IMPORT_ENERGY_ENTITY"))
};

return msg;

let prev = flow.get("prev", "persistent") || {solar:0, load:0, grid:0};
let cur = msg.payload;

function delta(a,b){ return Math.max(a-b,0); }

let d = {
    solar: delta(cur.solar, prev.solar),
    load: delta(cur.load, prev.load),
    grid: delta(cur.grid, prev.grid)
};

flow.set("prev", cur, "persistent");
msg.delta = d;
return msg;

const tz = env.get("ADDON_TIMEZONE") || "UTC";

const now = new Date();
const fmtDay = new Intl.DateTimeFormat("en-CA", { timeZone: tz, year:"numeric", month:"2-digit", day:"2-digit" });
const fmtMonth = new Intl.DateTimeFormat("en-CA", { timeZone: tz, year:"numeric", month:"2-digit" });
const fmtYear = new Intl.DateTimeFormat("en-CA", { timeZone: tz, year:"numeric" });

const dayKey = fmtDay.format(now);
const monthKey = fmtMonth.format(now);
const yearKey = fmtYear.format(now);

let keys = flow.get("keys", "persistent") || {};
let energy = flow.get("energy", "persistent") || {
    day:{solar:0,load:0,grid:0},
    month:{solar:0,load:0,grid:0},
    year:{solar:0,load:0,grid:0}
};

// RESET DAY
if (keys.day !== dayKey) {
    energy.day = {solar:0,load:0,grid:0};
}

// RESET MONTH
if (keys.month !== monthKey) {
    energy.month = {solar:0,load:0,grid:0};
}

// RESET YEAR
if (keys.year !== yearKey) {
    energy.year = {solar:0,load:0,grid:0};
}

keys = { day: dayKey, month: monthKey, year: yearKey };

flow.set("keys", keys, "persistent");
flow.set("energy", energy, "persistent");

msg.energy = energy;
return msg;

let energy = flow.get("energy", "persistent");
let d = msg.delta;

energy.day.solar += d.solar;
energy.day.load += d.load;
energy.day.grid += d.grid;

energy.month.solar += d.solar;
energy.month.load += d.load;
energy.month.grid += d.grid;

energy.year.solar += d.solar;
energy.year.load += d.load;
energy.year.grid += d.grid;

flow.set("energy", energy, "persistent");

msg.energy = energy;
return msg;

const price = Number(env.get("FIXED_IMPORT_PRICE")) || 0;

function calc(e){
    const real = e.grid * price;
    const theo = e.load * price;
    return {
        cost_real: real,
        cost_theoretical: theo,
        savings: theo - real
    };
}

msg.payload = {
    day: calc(msg.energy.day),
    month: calc(msg.energy.month),
    year: calc(msg.energy.year),
    energy: msg.energy
};

return msg;
